-- 📌 성경 사전(Bible Dictionary) 샘플 데이터 삽입
INSERT INTO dictionary (id, term, description, related_verses, created_at, updated_at)
VALUES (1, '은혜', '자격 없는 자에게 베풀어지는 호의와 선물로, 하나님이 인간에게 베푸시는 선하심을 가리킨다.', '에베소서 2:8-9, 요한복음 1:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (2, '믿음', '보이지 않는 것을 신뢰하고 의지하는 태도로, 하나님의 말씀과 약속을 신뢰하는 것을 의미한다.', '히브리서 11:1, 로마서 10:17', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (3, '의', '올바르고 정당한 상태를 뜻하는 개념으로, 하나님의 기준에 합한 상태를 가리킨다.', '로마서 1:17, 신명기 6:25', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (4, '칭의', '법정 용어로 의롭다고 선언하는 행위를 뜻하며, 하나님이 인간을 의롭다 하시는 선언을 가리킨다.', '로마서 5:1, 갈라디아서 2:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (5, '성화', '거룩해지는 과정을 의미하며, 하나님의 백성이 점차 거룩함에 이르는 삶의 변화를 가리킨다.', '데살로니가전서 4:3, 히브리서 12:14', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (6, '영화', '영광스럽게 됨을 의미하는 용어로, 하나님의 백성이 궁극적으로 영광에 이르는 상태를 가리킨다.', '로마서 8:30, 빌립보서 3:21', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (7, '회개', '잘못을 뉘우치고 방향을 돌이키는 행위로, 죄에서 떠나 하나님께로 돌아서는 것을 의미한다.', '사도행전 3:19, 잠언 28:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (8, '구원', '위험이나 멸망에서 건져냄을 뜻하는 말로, 죄와 심판에서의 건짐을 가리킨다.', '로마서 6:23, 시편 62:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (9, '언약', '당사자 사이에 맺어진 공식적인 약속으로, 하나님과 인간 사이에 맺어진 약속 관계를 의미한다.', '창세기 9:9, 예레미야 31:33', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (10, '율법', '규범과 법도를 의미하는 말로, 하나님이 주신 계명과 규례를 가리킨다.', '출애굽기 20:1-17, 시편 19:7', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (11, '복음', '기쁜 소식을 뜻하는 말로, 예수 그리스도와 관련된 소식이나 선포의 내용을 가리킨다.', '로마서 1:16, 고린도전서 15:3-4', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (12, '그리스도', '기름 부음을 받은 자를 뜻하는 칭호로, 신약에서는 예수에게 사용된 호칭이다.', '마태복음 16:16, 시편 2:2', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (13, '메시아', '기름 부음을 받은 자를 뜻하는 히브리어 표현으로, 구약과 유대 전통에서 기대된 인물을 가리킨다.', '이사야 9:6, 요한복음 1:41', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (14, '속죄', '죄와 관련된 문제를 덮거나 처리하는 행위를 뜻하며, 제사와 피의 사용과 연관되어 사용된다.', '레위기 17:11, 히브리서 9:12', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (15, '대속', '다른 이를 대신하여 값을 지불하거나 책임을 감당하는 행위를 의미한다.', '마가복음 10:45, 이사야 53:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (16, '부활', '죽은 자가 다시 살아나는 것을 의미하며, 죽음 이후의 생명 회복을 가리킨다.', '고린도전서 15:20, 요한복음 11:25', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (17, '재림', '다시 오는 것을 뜻하는 말로, 신약에서는 예수의 다시 오심을 가리켜 사용된다.', '마태복음 24:30, 데살로니가전서 4:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (18, '천국', '하늘의 나라를 뜻하는 표현으로, 복음서에서 하나님의 다스림을 가리켜 사용된다.', '마태복음 4:17, 요한계시록 21:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (19, '지옥', '형벌이나 심판과 관련된 장소나 상태를 가리키는 표현으로, 여러 이미지로 묘사된다.', '마태복음 25:46, 요한계시록 20:15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (20, '심판', '옳고 그름을 가려 판결하는 행위를 의미하며, 하나님이 행하시는 판단을 가리킨다.', '히브리서 9:27, 고린도후서 5:10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (21, '성령', '하나님의 영으로, 성부와 성자와 함께하시는 인격적인 하나님이시며 신자의 삶 가운데 임재하여 활동하신다.', '요한복음 14:26, 사도행전 1:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (22, '삼위일체', '하나님을 성부·성자·성령으로 함께 언급하는 성경의 표현을 설명하기 위해 사용되는 신학 용어이다.', '마태복음 28:19, 고린도후서 13:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (23, '예배', '존귀한 대상에게 존경과 경배를 드리는 행위로, 하나님께 드리는 경배를 가리킨다.', '요한복음 4:24, 로마서 12:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (24, '기도', '간구나 호소를 뜻하는 말로, 하나님께 말하거나 도움을 구하는 행위를 가리킨다.', '빌립보서 4:6, 마태복음 6:9-13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (25, '찬양', '칭찬하고 높이는 행위로, 하나님을 노래와 말로 높이는 것을 의미한다.', '시편 150:1-6, 히브리서 13:15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (26, '감사', '받은 것에 대해 고마움을 표현하는 행위로, 하나님께 감사의 표현을 드리는 것을 가리킨다.', '데살로니가전서 5:18, 시편 107:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (27, '교회', '부름받은 사람들의 모임을 뜻하는 말로, 신약에서는 믿는 자들의 공동체를 가리킨다.', '에베소서 1:23, 마태복음 16:18', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (28, '제자', '스승을 따르며 배우는 사람을 뜻하며, 복음서에서는 예수를 따르는 사람을 가리킨다.', '누가복음 9:23, 마태복음 28:19', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (29, '사도', '보냄을 받은 자를 뜻하는 말로, 신약에서는 특별한 사명을 위해 파송된 사람을 가리킨다.', '사도행전 1:8, 에베소서 2:20', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (30, '선교', '보냄을 의미하는 개념으로, 하나님의 메시지가 다른 지역과 민족에게 전해지는 활동을 가리킨다.', '마태복음 24:14, 사도행전 13:2', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (31, '사랑', '애정과 헌신을 의미하는 말로, 하나님과 이웃을 향한 태도와 행위를 가리킨다.', '고린도전서 13:4-7, 요한복음 13:34', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (32, '소망', '미래에 대한 기대를 뜻하는 개념으로, 하나님의 약속을 바라보는 태도를 가리킨다.', '로마서 15:13, 베드로전서 1:3', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (33, '겸손', '자신을 낮추는 태도를 의미하며, 하나님과 사람 앞에서 낮아짐을 가리킨다.', '빌립보서 2:3, 미가 6:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (34, '순종', '요구나 명령에 따르는 행위를 뜻하며, 하나님의 말씀에 따름을 가리킨다.', '사무엘상 15:22, 요한복음 14:15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (35, '거룩', '구별됨을 의미하는 말로, 하나님께 속한 상태를 가리킨다.', '레위기 19:2, 베드로전서 1:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (36, '성결', '깨끗함과 정결함을 뜻하는 개념으로, 죄와 더러움에서 벗어난 상태를 가리킨다.', '히브리서 12:14, 시편 51:10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (37, '섬김', '돕고 봉사하는 행위를 의미하며, 타인을 위한 낮아짐을 가리킨다.', '마가복음 10:45, 갈라디아서 5:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (38, '안식', '쉼을 의미하는 말로, 노동을 멈추고 쉼을 누리는 개념과 하나님 안에서의 쉼을 가리킨다.', '히브리서 4:9-10, 출애굽기 20:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (39, '시험', '사람의 상태를 드러내거나 검증하는 상황을 뜻하며, 신앙과 태도가 드러나는 계기를 가리킨다.', '야고보서 1:2-3, 마태복음 4:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (40, '유혹', '잘못된 선택으로 이끄는 자극을 의미하며, 죄로 향하게 하는 내적·외적 작용을 가리킨다.', '야고보서 1:14, 창세기 3:1-6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (41, '죄', '하나님의 뜻과 기준에서 벗어난 상태나 행위로, 하나님과의 관계가 단절된 상태를 포함한다.', '로마서 3:23, 이사야 59:2', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (42, '타락', '본래 상태에서 떨어짐을 의미하는 말로, 인간이 죄의 영향 아래 놓이게 된 상태를 가리킨다.', '창세기 3:6-7, 로마서 5:12', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (43, '속량', '값을 지불하고 자유롭게 함을 뜻하는 개념으로, 종이나 포로를 대가로 풀어주는 행위를 가리킨다.', '에베소서 1:7, 갈라디아서 4:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (44, '화목', '관계가 회복되어 평화가 이루어짐을 의미하며, 깨어진 관계가 다시 이어지는 상태를 가리킨다.', '로마서 5:10, 고린도후서 5:18', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (45, '양자', '법적으로 자녀로 받아들이는 행위를 뜻하며, 가족 관계에 편입되는 개념으로 사용된다.', '로마서 8:15, 갈라디아서 4:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (46, '영생', '끝이 없는 생명을 의미하는 말로, 하나님과 관련된 생명을 가리켜 사용된다.', '요한복음 17:3, 요한일서 5:11', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (47, '말씀', '말이나 선언을 뜻하는 표현으로, 하나님의 뜻과 계시를 가리켜 사용된다.', '요한복음 1:1, 히브리서 4:12', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (48, '계시', '숨겨진 것이 드러남을 의미하는 말로, 하나님이 자신과 뜻을 알리시는 행위를 가리킨다.', '히브리서 1:1-2, 로마서 1:20', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (49, '지혜', '사물을 분별하고 바르게 판단하는 능력을 뜻하며, 하나님을 경외함에서 나오는 깨달음을 가리킨다.', '잠언 1:7, 야고보서 1:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (50, '지식', '알고 인식함을 의미하는 말로, 하나님과 그 뜻을 아는 인식을 가리킨다.', '호세아 6:6, 골로새서 1:10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (51, '종말', '어떤 과정이나 시대의 끝을 의미하는 말로, 하나님의 역사와 관련된 마지막 시점을 가리킨다.', '마태복음 24:14, 요한계시록 22:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (52, '새 하늘과 새 땅', '새롭게 된 하늘과 땅을 뜻하는 표현으로, 장차 도래할 새로운 질서를 묘사하는 데 사용된다.', '요한계시록 21:1, 이사야 65:17', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (53, '왕국', '왕이 다스리는 영역을 의미하는 말로, 하나님의 통치와 권세를 가리켜 사용된다.', '마태복음 6:33, 시편 103:19', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (54, '하나님 나라', '하나님의 다스림을 의미하는 표현으로, 하나님의 권위와 통치가 미치는 범위를 가리킨다.', '누가복음 17:21, 마태복음 13:31', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (55, '중보', '두 당사자 사이에 서서 연결하는 역할을 뜻하며, 하나님과 사람 사이를 잇는 행위를 가리킨다.', '디모데전서 2:5, 히브리서 7:25', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (56, '제사', '신에게 제물을 바치는 의식을 의미하는 말로, 하나님께 드리는 예식 행위를 가리킨다.', '레위기 1:4, 히브리서 10:10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (57, '희생', '무언가를 내어주는 행위를 뜻하며, 제물이나 헌신의 행위를 가리킨다.', '로마서 12:1, 요한복음 15:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (58, '순교', '신앙이나 신념으로 인해 죽음을 맞는 일을 의미하며, 믿음으로 인해 죽임을 당한 일을 가리킨다.', '요한계시록 2:10, 사도행전 7:59', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (59, '충성', '맡겨진 대상이나 관계에 성실히 임하는 태도를 뜻하며, 하나님께 신실함을 보이는 태도를 가리킨다.', '마태복음 25:21, 고린도전서 4:2', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (60, '영광', '위엄과 존귀함을 나타내는 말로, 하나님의 위대함과 존엄을 표현하는 데 사용된다.', '이사야 6:3, 로마서 11:36', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (61, '창조', '없던 것을 만들어 냄을 의미하는 말로, 하나님이 만물을 존재하게 하신 행위를 가리킨다.', '창세기 1:1, 히브리서 11:3', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (62, '섭리', '사물을 이끌고 보존함을 뜻하는 개념으로, 하나님이 세계와 역사를 돌보며 이끄시는 모습을 설명할 때 사용된다.', '마태복음 10:29, 로마서 8:28', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (63, '주권', '최종적인 권한과 통제력을 의미하는 말로, 하나님께 속한 절대적 권위를 가리킨다.', '시편 115:3, 다니엘 4:35', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (64, '공의', '옳고 바름에 따른 판단을 뜻하는 개념으로, 하나님의 판단과 행위의 기준을 가리킨다.', '시편 89:14, 로마서 2:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (65, '자비', '불쌍히 여기고 긍휼히 여김을 의미하는 말로, 하나님이 사람을 향해 보이시는 태도를 가리킨다.', '시편 103:8, 누가복음 6:36', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (66, '긍휼', '고통이나 어려움에 대한 깊은 동정을 뜻하는 말로, 고난받는 이를 향한 마음을 가리킨다.', '마태복음 9:36, 애가 3:22', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
